483→DEFINE FUNCTION fn::entity_search_workspace($q: string, $limit: int, $workspace: record<workspace>) {
484→  LET $query = string::lowercase(string::trim($q));
485→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
486→
487→  LET $task_rows = SELECT
488→    id,
489→    "task" AS kind,
490→    title AS text,
491→    extraction_confidence AS confidence,
492→    source_message AS sourceMessage,
493→    priority,
494→    created_at
495→  FROM task
496→  WHERE workspace = $workspace
497→    AND extraction_confidence != NONE
498→    AND string::contains(string::lowercase(title), $query)
499→  ORDER BY created_at DESC
500→  LIMIT $safe_limit;
501→
502→  LET $decision_rows = SELECT
503→    id,
504→    "decision" AS kind,
505→    summary AS text,
506→    extraction_confidence AS confidence,
507→    source_message AS sourceMessage,
508→    priority,
509→    created_at
510→  FROM decision
511→  WHERE workspace = $workspace
512→    AND extraction_confidence != NONE
513→    AND string::contains(string::lowercase(summary), $query)
514→  ORDER BY created_at DESC
515→  LIMIT $safe_limit;
516→
517→  LET $question_rows = SELECT
518→    id,
519→    "question" AS kind,
520→    text AS text,
521→    extraction_confidence AS confidence,
522→    source_message AS sourceMessage,
523→    priority,
524→    created_at
525→  FROM question
526→  WHERE workspace = $workspace
527→    AND extraction_confidence != NONE
528→    AND string::contains(string::lowercase(text), $query)
529→  ORDER BY created_at DESC
530→  LIMIT $safe_limit;
531→
532→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
533→};
