631→DEFINE FUNCTION fn::workspace_entity_ids($ws: record<workspace>) {
632→  LET $projects = (SELECT VALUE out FROM has_project WHERE `in` = $ws);
633→  LET $features = (SELECT VALUE out FROM has_feature WHERE `in` IN $projects);
634→  LET $tasks = (SELECT VALUE out FROM has_task WHERE `in` IN $features);
635→  LET $belongs_project = (SELECT VALUE `in` FROM belongs_to WHERE out IN $projects);
636→  LET $belongs_feature = (SELECT VALUE `in` FROM belongs_to WHERE out IN $features);
637→  LET $persons = (SELECT VALUE `in` FROM member_of WHERE out = $ws);
638→  LET $provenance = (
639→    SELECT VALUE out FROM extraction_relation
640→    WHERE `in` IN (
641→      SELECT VALUE id FROM message
642→      WHERE conversation IN (
643→        SELECT VALUE id FROM conversation WHERE workspace = $ws
644→      )
645→    )
646→  );
647→  RETURN array::distinct(
648→    $projects + $features + $tasks +
649→    $belongs_project + $belongs_feature +
650→    $persons + $provenance
651→  );
652→};
653→
654→DEFINE FUNCTION fn::project_entity_ids($ws: record<workspace>, $project: record<project>) {
655→  LET $features = (SELECT VALUE out FROM has_feature WHERE `in` = $project);
656→  LET $tasks = (SELECT VALUE out FROM has_task WHERE `in` IN $features);
657→  LET $belongs_project = (SELECT VALUE `in` FROM belongs_to WHERE out = $project);
658→  LET $belongs_feature = (SELECT VALUE `in` FROM belongs_to WHERE out IN $features);
659→  LET $persons = (SELECT VALUE `in` FROM member_of WHERE out = $ws);
660→  LET $provenance = (
661→    SELECT VALUE out FROM extraction_relation
662→    WHERE `in` IN (
663→      SELECT VALUE id FROM message
664→      WHERE conversation IN (
665→        SELECT VALUE id FROM conversation WHERE workspace = $ws
666→      )
667→    )
668→  );
669→  RETURN array::distinct(
670→    [$project] + $features + $tasks +
671→    $belongs_project + $belongs_feature +
672→    $persons + $provenance
673→  );
674→};
