182→async function handleWorkspaceBootstrap(deps: ServerDependencies, workspaceId: string): Promise<Response> {
183→  const startedAt = performance.now();
184→  logInfo("workspace.bootstrap.started", "Workspace bootstrap started", { workspaceId });
185→
186→  try {
187→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
188→    const workspace = await deps.surreal.select<WorkspaceRow>(workspaceRecord);
189→    if (!workspace) {
190→      throw new HttpError(404, `workspace not found: ${workspaceId}`);
191→    }
192→
193→    const conversationRecord = await resolveWorkspaceBootstrapConversation(deps, workspaceRecord);
194→    const conversationId = conversationRecord.id as string;
195→    const rawMessages = await loadMessagesWithInheritance(deps.surreal, conversationId, 80);
196→
197→    const messages = rawMessages.map((row) => ({
198→      id: row.id,
199→      role: row.role,
200→      text: row.text,
201→      createdAt: toIsoString(row.createdAt),
202→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
203→      ...(row.inherited ? { inherited: true } : {}),
204→      ...(row.subagent_traces && row.subagent_traces.length > 0 ? { subagentTraces: row.subagent_traces } : {}),
205→    } satisfies WorkspaceBootstrapMessage));
206→
207→    const seeds = await loadWorkspaceSeeds(deps, workspaceRecord, 40);
208→    const onboardingState = toOnboardingState(workspace);
209→    const sidebar = await buildWorkspaceConversationSidebar(deps.surreal, workspaceRecord);
210→
211→    const payload: WorkspaceBootstrapResponse = {
212→      workspaceId: workspace.id.id as string,
213→      workspaceName: workspace.name,
214→      ...(workspace.description ? { workspaceDescription: workspace.description } : {}),
215→      onboardingComplete: workspace.onboarding_complete,
216→      onboardingState,
217→      conversationId: conversationRecord.id as string,
218→      messages,
219→      seeds,
220→      sidebar,
221→    };
222→
223→    logInfo("workspace.bootstrap.completed", "Workspace bootstrap completed", {
224→      workspaceId,
225→      conversationId: conversationRecord.id as string,
226→      messageCount: messages.length,
227→      seedCount: seeds.length,
228→      durationMs: elapsedMs(startedAt),
229→    });
230→
231→    return jsonResponse(payload, 200);
232→  } catch (error) {
233→    if (error instanceof HttpError) {
234→      logWarn("workspace.bootstrap.http_error", "Workspace bootstrap failed with client-facing error", {
235→        workspaceId,
236→        statusCode: error.status,
237→      });
238→      return jsonError(error.message, error.status);
239→    }
240→
241→    logError("workspace.bootstrap.failed", "Workspace bootstrap failed", error, { workspaceId });
242→    const errorText = error instanceof Error ? error.message : "workspace bootstrap failed";
243→    return jsonError(errorText, 500);
244→  }
245→}
