401→async function handleWorkspaceConversation(
402→  deps: ServerDependencies,
403→  workspaceId: string,
404→  conversationId: string,
405→): Promise<Response> {
406→  const startedAt = performance.now();
407→  logInfo("workspace.conversation.started", "Workspace conversation request started", {
408→    workspaceId,
409→    conversationId,
410→  });
411→
412→  try {
413→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
414→    const conversationRecord = new RecordId("conversation", conversationId);
415→    const conversation = await deps.surreal.select<{
416→      id: RecordId<"conversation", string>;
417→      workspace: RecordId<"workspace", string>;
418→      discusses?: RecordId;
419→    }>(conversationRecord);
420→
421→    if (!conversation) {
422→      throw new HttpError(404, `conversation not found: ${conversationId}`);
423→    }
424→
425→    if ((conversation.workspace.id as string) !== (workspaceRecord.id as string)) {
426→      throw new HttpError(400, "conversation does not belong to workspace");
427→    }
428→
429→    const rawMessages = await loadMessagesWithInheritance(deps.surreal, conversationId, 80);
430→
431→    const messages = rawMessages.map((row) => ({
432→      id: row.id,
433→      role: row.role,
434→      text: row.text,
435→      createdAt: toIsoString(row.createdAt),
436→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
437→      ...(row.inherited ? { inherited: true } : {}),
438→      ...(row.subagent_traces && row.subagent_traces.length > 0 ? { subagentTraces: row.subagent_traces } : {}),
439→    } satisfies WorkspaceBootstrapMessage));
440→
441→    let discussEntity: DiscussEntitySummary | undefined;
442→    if (conversation.discusses) {
443→      const entityRecord = conversation.discusses as GraphEntityRecord;
444→      const name = await readEntityName(deps.surreal, entityRecord);
445→      if (name) {
446→        const entityRow = await deps.surreal.select<Record<string, unknown>>(entityRecord);
447→        discussEntity = {
448→          id: `${entityRecord.table.name}:${entityRecord.id as string}`,
449→          kind: entityRecord.table.name as EntityKind,
450→          name,
451→          ...(entityRow && typeof entityRow.status === "string" ? { status: entityRow.status } : {}),
452→        };
453→      }
454→    }
455→
456→    const payload: WorkspaceConversationResponse = {
457→      conversationId,
458→      messages,
459→      ...(discussEntity ? { discussEntity } : {}),
460→    };
461→
462→    logInfo("workspace.conversation.completed", "Workspace conversation request completed", {
463→      workspaceId,
464→      conversationId,
465→      messageCount: messages.length,
466→      durationMs: elapsedMs(startedAt),
467→    });
468→
469→    return jsonResponse(payload, 200);
470→  } catch (error) {
471→    if (error instanceof HttpError) {
472→      logWarn("workspace.conversation.http_error", "Workspace conversation failed with client-facing error", {
473→        workspaceId,
474→        conversationId,
475→        statusCode: error.status,
476→      });
477→      return jsonError(error.message, error.status);
478→    }
479→
480→    logError("workspace.conversation.failed", "Workspace conversation request failed", error, {
481→      workspaceId,
482→      conversationId,
483→    });
484→    const errorText = error instanceof Error ? error.message : "workspace conversation failed";
485→    return jsonError(errorText, 500);
486→  }
487→}
