  1→// ---------------------------------------------------------------------------
  2→// Types
  3→// ---------------------------------------------------------------------------
  4→
  5→export type WorktreeInfo = {
  6→  worktreePath: string;
  7→  branchName: string;
  8→};
  9→
 10→export type DiffResult = {
 11→  files: Array<{
 12→    path: string;
 13→    status: string;
 14→    additions: number;
 15→    deletions: number;
 16→  }>;
 17→  rawDiff: string;
 18→  stats: { filesChanged: number; insertions: number; deletions: number };
 19→};
 20→
 21→export type WorktreeErrorCode = "WORKTREE_EXISTS" | "GIT_ERROR";
 22→
 23→export type WorktreeError = {
 24→  code: WorktreeErrorCode;
 25→  message: string;
 26→};
 27→
 28→export type WorktreeResult<T> =
 29→  | { ok: true; value: T }
 30→  | { ok: false; error: WorktreeError };
 31→
 32→// ---------------------------------------------------------------------------
 33→// Shell executor port (injected dependency)
 34→// ---------------------------------------------------------------------------
 35→
 36→export type ShellExecResult = {
 37→  exitCode: number;
 38→  stdout: string;
 39→  stderr: string;
 40→};
 41→
 42→export type ShellExec = (
 43→  command: string,
 44→  args: string[],
 45→  cwd: string,
 46→) => Promise<ShellExecResult>;
 47→
 48→// ---------------------------------------------------------------------------
 49→// Pure helpers: path and branch construction
 50→// ---------------------------------------------------------------------------
 51→
 52→const WORKTREE_DIR = ".brain/worktrees";
 53→const BRANCH_PREFIX = "agent/";
 54→const WORKTREE_PREFIX = "agent-";
 55→
 56→export function buildWorktreePath(repoRoot: string, taskSlug: string): string {
 57→  return `${repoRoot}/${WORKTREE_DIR}/${WORKTREE_PREFIX}${taskSlug}`;
 58→}
 59→
 60→export function buildBranchName(taskSlug: string): string {
 61→  return `${BRANCH_PREFIX}${taskSlug}`;
 62→}
 63→
 64→function worktreeRelativePath(taskSlug: string): string {
 65→  return `${WORKTREE_DIR}/${WORKTREE_PREFIX}${taskSlug}`;
 66→}
 67→
 68→function taskSlugFromBranch(branchName: string): string {
 69→  return branchName.replace(BRANCH_PREFIX, "");
 70→}
 71→
 72→// ---------------------------------------------------------------------------
 73→// Error constructors
 74→// ---------------------------------------------------------------------------
 75→
 76→function worktreeExists(stderr: string): WorktreeResult<never> {
 77→  return {
 78→    ok: false,
 79→    error: {
 80→      code: "WORKTREE_EXISTS",
 81→      message: `Worktree already exists: ${stderr}`,
 82→    },
 83→  };
 84→}
 85→
 86→function gitError(stderr: string): WorktreeResult<never> {
 87→  return {
 88→    ok: false,
 89→    error: {
 90→      code: "GIT_ERROR",
 91→      message: `Git command failed: ${stderr}`,
 92→    },
 93→  };
 94→}
 95→
 96→// ---------------------------------------------------------------------------
 97→// createWorktree — creates worktree with new branch
 98→// ---------------------------------------------------------------------------
 99→
100→export async function createWorktree(
101→  exec: ShellExec,
102→  repoRoot: string,
103→  taskSlug: string,
104→): Promise<WorktreeResult<WorktreeInfo>> {
105→  const branchName = buildBranchName(taskSlug);
106→  const relativePath = worktreeRelativePath(taskSlug);
107→
108→  const result = await exec(
109→    "git",
110→    ["worktree", "add", "-b", branchName, relativePath],
111→    repoRoot,
112→  );
113→
114→  if (result.exitCode !== 0) {
115→    if (result.stderr.includes("already exists")) {
116→      return worktreeExists(result.stderr);
117→    }
118→    return gitError(result.stderr);
119→  }
120→
121→  return {
122→    ok: true,
123→    value: {
124→      worktreePath: buildWorktreePath(repoRoot, taskSlug),
125→      branchName,
126→    },
127→  };
128→}
129→
130→// ---------------------------------------------------------------------------
131→// removeWorktree — idempotent removal of worktree and branch
132→// ---------------------------------------------------------------------------
133→
134→export async function removeWorktree(
135→  exec: ShellExec,
136→  repoRoot: string,
137→  branchName: string,
138→): Promise<WorktreeResult<void>> {
139→  const taskSlug = taskSlugFromBranch(branchName);
140→  const relativePath = worktreeRelativePath(taskSlug);
141→
142→  // Remove worktree (ignore failure — idempotent)
143→  await exec(
144→    "git",
145→    ["worktree", "remove", relativePath, "--force"],
146→    repoRoot,
147→  );
148→
149→  // Delete branch (ignore failure — idempotent)
150→  await exec("git", ["branch", "-D", branchName], repoRoot);
151→
152→  return { ok: true, value: undefined };
153→}
