155→// ---------------------------------------------------------------------------
156→// Pure parsers: git diff output
157→// ---------------------------------------------------------------------------
158→
159→type NumstatEntry = { path: string; additions: number; deletions: number };
160→type NameStatusEntry = { path: string; status: string };
161→
162→export function parseNumstat(output: string): NumstatEntry[] {
163→  return output
164→    .split("\n")
165→    .filter((line) => line.trim() !== "")
166→    .map((line) => {
167→      const [addStr, delStr, ...pathParts] = line.split("\t");
168→      return {
169→        path: pathParts.join("\t"),
170→        additions: addStr === "-" ? 0 : parseInt(addStr, 10),
171→        deletions: delStr === "-" ? 0 : parseInt(delStr, 10),
172→      };
173→    });
174→}
175→
176→export function parseNameStatus(output: string): NameStatusEntry[] {
177→  return output
178→    .split("\n")
179→    .filter((line) => line.trim() !== "")
180→    .map((line) => {
181→      const [status, ...pathParts] = line.split("\t");
182→      return { path: pathParts.join("\t"), status };
183→    });
184→}
185→
186→export function combineDiffFileEntries(
187→  numstat: NumstatEntry[],
188→  nameStatus: NameStatusEntry[],
189→): DiffResult["files"] {
190→  const statusByPath = new Map(nameStatus.map((e) => [e.path, e.status]));
191→  return numstat.map((entry) => ({
192→    path: entry.path,
193→    status: statusByPath.get(entry.path) ?? "M",
194→    additions: entry.additions,
195→    deletions: entry.deletions,
196→  }));
197→}
198→
199→// ---------------------------------------------------------------------------
200→// getDiff — generates diff between main and agent branch
201→// ---------------------------------------------------------------------------
202→
203→export async function getDiff(
204→  exec: ShellExec,
205→  repoRoot: string,
206→  branchName: string,
207→): Promise<WorktreeResult<DiffResult>> {
208→  const diffRef = `main...${branchName}`;
209→
210→  const numstatResult = await exec(
211→    "git",
212→    ["diff", "--numstat", diffRef],
213→    repoRoot,
214→  );
215→  if (numstatResult.exitCode !== 0) {
216→    return gitError(numstatResult.stderr);
217→  }
218→
219→  const nameStatusResult = await exec(
220→    "git",
221→    ["diff", "--name-status", diffRef],
222→    repoRoot,
223→  );
224→  if (nameStatusResult.exitCode !== 0) {
225→    return gitError(nameStatusResult.stderr);
226→  }
227→
228→  const rawDiffResult = await exec("git", ["diff", diffRef], repoRoot);
229→  if (rawDiffResult.exitCode !== 0) {
230→    return gitError(rawDiffResult.stderr);
231→  }
232→
233→  const numstatEntries = parseNumstat(numstatResult.stdout);
