315→      return lifecycle.abortOrchestratorSession({
316→        surreal: wiringDeps.surreal,
317→        shellExec: wiringDeps.shellExec,
318→        repoRoot: wiringDeps.repoRoot,
319→        sessionId,
320→        endAgentSession: queries.endAgentSession,
321→      });
322→    },
323→
324→    acceptSession: async (sessionId, summary) => {
325→      const [lifecycle, queries] = await Promise.all([
326→        lifecycleImport,
327→        queriesImport,
328→      ]);
329→      return lifecycle.acceptOrchestratorSession({
330→        surreal: wiringDeps.surreal,
331→        sessionId,
332→        summary,
333→        endAgentSession: queries.endAgentSession,
334→      });
335→    },
336→
337→    getReview: async (sessionId) => {
338→      const [lifecycle, worktreeManager] = await Promise.all([
339→        lifecycleImport,
340→        import("./worktree-manager"),
341→      ]);
342→      return lifecycle.getOrchestratorReview({
343→        surreal: wiringDeps.surreal,
344→        sessionId,
345→        getDiff: (branchName: string) =>
346→          worktreeManager.getDiff(wiringDeps.shellExec, wiringDeps.repoRoot, branchName),
347→        getTaskTitle: async (taskId: string) => {
348→          const { RecordId } = await import("surrealdb");
349→          const taskRecord = new RecordId("task", taskId);
350→          const rows = (await wiringDeps.surreal.query(
351→            `SELECT title FROM $task;`,
352→            { task: taskRecord },
353→          )) as Array<Array<{ title: string }>>;
354→          return rows[0]?.[0]?.title ?? "";
355→        },
356→      });
357→    },
358→
359→    rejectSession: async (sessionId, feedback) => {
360→      const lifecycle = await lifecycleImport;
361→      return lifecycle.rejectOrchestratorSession({
362→        surreal: wiringDeps.surreal,
363→        sessionId,
364→        feedback,
365→      });
366→    },
367→  };
368→
369→  const handlers = createOrchestratorRouteHandlers(routeDeps);
370→
371→  const streamHandler = wiringDeps.sseRegistry
372→    ? createStreamRouteHandler({ sseRegistry: wiringDeps.sseRegistry })
373→    : undefined;
374→
375→  return {
