 21→  worktreeBranch?: string;
 22→  startedAt: string;
 23→  lastEventAt?: string;
 24→};
 25→
 26→export type SessionReviewResponse = {
 27→  agentSessionId: string;
 28→  taskId: string;
 29→  taskTitle: string;
 30→  summary?: string;
 31→  diff: {
 32→    files: Array<{
 33→      path: string;
 34→      status: "added" | "modified" | "deleted";
 35→      additions: number;
 36→      deletions: number;
 37→    }>;
 38→    rawDiff: string;
 39→    stats: {
 40→      filesChanged: number;
 41→      insertions: number;
 42→      deletions: number;
 43→    };
 44→  };
 45→  session: {
 46→    startedAt: string;
 47→    lastEventAt?: string;
 48→    decisionsCount: number;
 49→    questionsCount: number;
 50→    observationsCount: number;
 51→  };
 52→};
 53→
 54→export type AcceptSessionResponse = {
 55→  accepted: boolean;
 56→  taskStatus: string;
 57→};
 58→
 59→export type RejectSessionResponse = {
 60→  rejected: boolean;
 61→  continuing: boolean;
 62→};
 63→
 64→export type AbortSessionResponse = {
 65→  aborted: boolean;
 66→  taskStatus: string;
 67→};
 68→
 69→// ---------------------------------------------------------------------------
 70→// Internal Helpers
 71→// ---------------------------------------------------------------------------
 72→
 73→function orchestratorUrl(workspaceId: string, ...segments: string[]): string {
 74→  const base = `/api/orchestrator/${encodeURIComponent(workspaceId)}`;
 75→  if (segments.length === 0) return base;
 76→  return `${base}/${segments.map(encodeURIComponent).join("/")}`;
 77→}
 78→
 79→async function orchestratorFetch<T>(url: string, init?: RequestInit): Promise<T> {
 80→  const response = await fetch(url, init);
 81→  if (!response.ok) {
 82→    const text = await response.text();
 83→    throw new Error(`Orchestrator request failed (${response.status}): ${text}`);
 84→  }
 85→  return (await response.json()) as T;
 86→}
 87→
 88→// ---------------------------------------------------------------------------
 89→// API Functions
 90→// ---------------------------------------------------------------------------
 91→
 92→export function assignAgent(
 93→  workspaceId: string,
 94→  taskId: string,
 95→): Promise<AssignAgentResponse> {
 96→  return orchestratorFetch<AssignAgentResponse>(
 97→    orchestratorUrl(workspaceId, "assign"),
 98→    {
 99→      method: "POST",
100→      headers: { "Content-Type": "application/json" },
101→      body: JSON.stringify({ taskId }),
102→    },
103→  );
104→}
105→
106→export function getSessionStatus(
107→  workspaceId: string,
108→  sessionId: string,
109→): Promise<SessionStatusResponse> {
110→  return orchestratorFetch<SessionStatusResponse>(
111→    orchestratorUrl(workspaceId, "sessions", sessionId),
112→  );
113→}
114→
115→export function getSessionReview(
116→  workspaceId: string,
117→  sessionId: string,
118→): Promise<SessionReviewResponse> {
119→  return orchestratorFetch<SessionReviewResponse>(
120→    orchestratorUrl(workspaceId, "sessions", sessionId, "review"),
121→  );
122→}
123→
124→export function acceptSession(
125→  workspaceId: string,
126→  sessionId: string,
127→  summary?: string,
128→): Promise<AcceptSessionResponse> {
129→  return orchestratorFetch<AcceptSessionResponse>(
130→    orchestratorUrl(workspaceId, "sessions", sessionId, "accept"),
131→    {
132→      method: "POST",
133→      headers: { "Content-Type": "application/json" },
134→      body: JSON.stringify(summary !== undefined ? { summary } : {}),
135→    },
136→  );
137→}
138→
139→export function rejectSession(
140→  workspaceId: string,
141→  sessionId: string,
142→  feedback: string,
143→): Promise<RejectSessionResponse> {
144→  return orchestratorFetch<RejectSessionResponse>(
145→    orchestratorUrl(workspaceId, "sessions", sessionId, "reject"),
146→    {
147→      method: "POST",
148→      headers: { "Content-Type": "application/json" },
149→      body: JSON.stringify({ feedback }),
150→    },
151→  );
152→}
153→
154→export function abortSession(
155→  workspaceId: string,
156→  sessionId: string,
157→): Promise<AbortSessionResponse> {
158→  return orchestratorFetch<AbortSessionResponse>(
159→    orchestratorUrl(workspaceId, "sessions", sessionId, "abort"),
160→    {
161→      method: "POST",
162→      headers: { "Content-Type": "application/json" },
163→    },
164→  );
165→}
