46→          )}
47→        </span>
48→      </button>
49→      {expanded && (
50→        <div className="diff-file-content">
51→          {section.lines.map((line, index) => (
52→            <DiffLine key={index} line={line} />
53→          ))}
54→        </div>
55→      )}
56→    </div>
57→  );
58→}
