60→export function DiffViewer({ rawDiff }: { rawDiff: string }) {
61→  const sections = parseDiff(rawDiff);
62→
63→  if (sections.length === 0) {
64→    return <div className="diff-viewer diff-viewer--empty">No changes</div>;
65→  }
66→
67→  const totalAdditions = sections.reduce((sum, s) => sum + s.additions, 0);
68→  const totalDeletions = sections.reduce((sum, s) => sum + s.deletions, 0);
69→
70→  return (
71→    <div className="diff-viewer">
72→      <div className="diff-summary">
73→        <span className="diff-summary-files">{sections.length} files changed</span>
74→        <span className="diff-stat-additions">+{totalAdditions}</span>
75→        <span className="diff-stat-deletions">-{totalDeletions}</span>
76→      </div>
77→      <div className="diff-file-list">
78→        {sections.map((section) => (
79→          <FileSection key={section.path} section={section} />
80→        ))}
81→      </div>
82→    </div>
83→  );
84→}
