  1→import { randomUUID } from "node:crypto";
  2→import { RecordId } from "surrealdb";
  3→import type {
  4→  CreateWorkspaceResponse,
  5→  DiscussEntitySummary,
  6→  OnboardingSeedItem,
  7→  WorkspaceBootstrapMessage,
  8→  WorkspaceBootstrapResponse,
  9→  WorkspaceConversationResponse,
 10→  SourceKind,
 11→  EntityKind,
 12→} from "../../shared/contracts";
 13→import { readEntityName } from "../graph/queries";
 14→import { readEntityText } from "../extraction/entity-text";
 15→import type { GraphEntityRecord, SourceRecord } from "../extraction/types";
 16→import { HttpError } from "../http/errors";
 17→import { elapsedMs, logDebug, logError, logInfo, logWarn } from "../http/observability";
 18→import { parseCreateWorkspaceRequest } from "../http/parsing";
 19→import { jsonError, jsonResponse, toIsoString } from "../http/response";
 20→import type { ServerDependencies } from "../runtime/types";
 21→import { toOnboardingState } from "../onboarding/onboarding-state";
 22→import { resolveWorkspaceRecord } from "./workspace-scope";
 23→import { buildWorkspaceConversationSidebar } from "./conversation-sidebar";
 24→import { loadMessagesWithInheritance } from "../chat/branch-chain";
 25→
 26→type WorkspaceRow = {
 27→  id: RecordId<"workspace", string>;
 28→  name: string;
 29→  description?: string;
 30→  status: string;
 31→  onboarding_complete: boolean;
 32→  onboarding_turn_count: number;
 33→  onboarding_summary_pending: boolean;
 34→};
 35→
 36→type ProvenanceEdgeRow = {
 37→  id: RecordId<"extraction_relation", string>;
 38→  in: SourceRecord;
 39→  out: GraphEntityRecord;
 40→  confidence: number;
 41→  extracted_at: Date | string;
 42→};
 43→
 44→export function createWorkspaceRouteHandlers(deps: ServerDependencies): {
 45→  handleCreateWorkspace: (request: Request) => Promise<Response>;
 46→  handleWorkspaceBootstrap: (workspaceId: string) => Promise<Response>;
 47→  handleWorkspaceSidebar: (workspaceId: string) => Promise<Response>;
 48→  handleWorkspaceConversation: (workspaceId: string, conversationId: string) => Promise<Response>;
 49→} {
 50→  return {
 51→    handleCreateWorkspace: (request: Request) => handleCreateWorkspace(deps, request),
 52→    handleWorkspaceBootstrap: (workspaceId: string) => handleWorkspaceBootstrap(deps, workspaceId),
 53→    handleWorkspaceSidebar: (workspaceId: string) => handleWorkspaceSidebar(deps, workspaceId),
 54→    handleWorkspaceConversation: (workspaceId: string, conversationId: string) =>
 55→      handleWorkspaceConversation(deps, workspaceId, conversationId),
 56→  };
 57→}
 58→
 59→async function handleCreateWorkspace(deps: ServerDependencies, request: Request): Promise<Response> {
 60→  const startedAt = performance.now();
 61→  logInfo("workspace.create.started", "Workspace creation started");
 62→
 63→  const session = await deps.auth.api.getSession({ headers: request.headers });
 64→  if (!session?.user?.id) {
 65→    return jsonError("authentication required", 401);
 66→  }
 67→
 68→  let body: unknown;
 69→  try {
 70→    body = await request.json();
 71→  } catch {
 72→    return jsonError("Request body must be valid JSON", 400);
 73→  }
 74→
 75→  const parsed = parseCreateWorkspaceRequest(body);
 76→  if (!parsed.ok) {
 77→    return jsonError(parsed.error, 400);
 78→  }
 79→
 80→  logDebug("http.request.validated", "Workspace request validated");
 81→
 82→  const now = new Date();
 83→  const workspaceId = randomUUID();
 84→  const conversationId = randomUUID();
 85→
 86→  const workspaceRecord = new RecordId("workspace", workspaceId);
 87→  const conversationRecord = new RecordId("conversation", conversationId);
 88→  const ownerRecord = new RecordId("person", session.user.id);
 89→  const starterMessageRecord = new RecordId("message", randomUUID());
 90→  const hasDescription = parsed.data.description !== undefined;
 91→  const ownerName = session.user.name ?? "there";
 92→
 93→  const starterSuggestions = hasDescription
 94→    ? [
 95→        "Describe your first project",
 96→        "Share the biggest current bottleneck",
 97→        "Upload a plan or spec to extract",
 98→      ]
 99→    : [
100→        "Describe your business and goals",
101→        "Share the biggest current bottleneck",
102→        "Upload a plan or spec to extract",
103→      ];
104→
105→  const starterMessage = hasDescription
106→    ? [
107→        `Hey ${ownerName}!`,
108→        `Got it — I'll help you organize ${parsed.data.name}.`,
109→        "What are the main projects or product areas you want to track?",
110→        "You can also drop in a document (plan, spec, PRD) and I'll extract everything from it.",
111→      ].join(" ")
112→    : [
113→        `Hey ${ownerName}!`,
114→        "I'm ready to help you build out your workspace.",
115→        "Tell me about what you're working on - what's the main project or business you want to track here?",
116→        "If you have an existing document (like a plan or spec), you can drop it in and I'll extract everything from it.",
117→      ].join(" ");
118→
119→  const transaction = await deps.surreal.beginTransaction();
120→  try {
121→    await transaction.create(workspaceRecord).content({
122→      name: parsed.data.name,
123→      ...(parsed.data.description ? { description: parsed.data.description } : {}),
124→      status: "active",
125→      onboarding_complete: false,
126→      onboarding_turn_count: 0,
127→      onboarding_summary_pending: false,
128→      onboarding_started_at: now,
129→      created_at: now,
130→      updated_at: now,
131→    });
132→
133→    await transaction.relate(ownerRecord, new RecordId("member_of", randomUUID()), workspaceRecord, {
134→      role: "owner",
135→      added_at: now,
136→    }).output("after");
137→
138→    await transaction.create(conversationRecord).content({
139→      createdAt: now,
140→      updatedAt: now,
141→      workspace: workspaceRecord,
142→      source: "onboarding",
143→      title: "Onboarding",
144→      title_source: "message",
145→    });
146→
147→    await transaction.create(starterMessageRecord).content({
148→      conversation: conversationRecord,
149→      role: "assistant",
150→      text: starterMessage,
151→      suggestions: starterSuggestions,
152→      createdAt: now,
153→    });
154→
155→    await transaction.commit();
156→  } catch (error) {
157→    await transaction.cancel();
158→    logError("workspace.create.failed", "Workspace creation failed", error, {
159→      workspaceId,
160→      conversationId,
161→    });
162→    const errorText = error instanceof Error ? error.message : "workspace creation failed";
163→    return jsonError(errorText, 500);
164→  }
165→
166→  const response: CreateWorkspaceResponse = {
167→    workspaceId,
168→    workspaceName: parsed.data.name,
169→    conversationId,
170→    onboardingComplete: false,
171→  };
172→
173→  logInfo("workspace.create.completed", "Workspace creation completed", {
174→    workspaceId,
175→    conversationId,
176→    durationMs: elapsedMs(startedAt),
177→  });
178→
179→  return jsonResponse(response, 200);
180→}
181→
182→async function handleWorkspaceBootstrap(deps: ServerDependencies, workspaceId: string): Promise<Response> {
183→  const startedAt = performance.now();
184→  logInfo("workspace.bootstrap.started", "Workspace bootstrap started", { workspaceId });
185→
186→  try {
187→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
188→    const workspace = await deps.surreal.select<WorkspaceRow>(workspaceRecord);
189→    if (!workspace) {
190→      throw new HttpError(404, `workspace not found: ${workspaceId}`);
191→    }
192→
193→    const conversationRecord = await resolveWorkspaceBootstrapConversation(deps, workspaceRecord);
194→    const conversationId = conversationRecord.id as string;
195→    const rawMessages = await loadMessagesWithInheritance(deps.surreal, conversationId, 80);
196→
197→    const messages = rawMessages.map((row) => ({
198→      id: row.id,
199→      role: row.role,
200→      text: row.text,
201→      createdAt: toIsoString(row.createdAt),
202→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
203→      ...(row.inherited ? { inherited: true } : {}),
204→      ...(row.subagent_traces && row.subagent_traces.length > 0 ? { subagentTraces: row.subagent_traces } : {}),
205→    } satisfies WorkspaceBootstrapMessage));
206→
207→    const seeds = await loadWorkspaceSeeds(deps, workspaceRecord, 40);
208→    const onboardingState = toOnboardingState(workspace);
209→    const sidebar = await buildWorkspaceConversationSidebar(deps.surreal, workspaceRecord);
210→
211→    const payload: WorkspaceBootstrapResponse = {
212→      workspaceId: workspace.id.id as string,
213→      workspaceName: workspace.name,
214→      ...(workspace.description ? { workspaceDescription: workspace.description } : {}),
215→      onboardingComplete: workspace.onboarding_complete,
216→      onboardingState,
217→      conversationId: conversationRecord.id as string,
218→      messages,
219→      seeds,
220→      sidebar,
221→    };
222→
223→    logInfo("workspace.bootstrap.completed", "Workspace bootstrap completed", {
224→      workspaceId,
225→      conversationId: conversationRecord.id as string,
226→      messageCount: messages.length,
227→      seedCount: seeds.length,
228→      durationMs: elapsedMs(startedAt),
229→    });
230→
231→    return jsonResponse(payload, 200);
232→  } catch (error) {
233→    if (error instanceof HttpError) {
234→      logWarn("workspace.bootstrap.http_error", "Workspace bootstrap failed with client-facing error", {
235→        workspaceId,
236→        statusCode: error.status,
237→      });
238→      return jsonError(error.message, error.status);
239→    }
240→
241→    logError("workspace.bootstrap.failed", "Workspace bootstrap failed", error, { workspaceId });
242→    const errorText = error instanceof Error ? error.message : "workspace bootstrap failed";
243→    return jsonError(errorText, 500);
244→  }
245→}
246→
247→async function resolveWorkspaceBootstrapConversation(
248→  deps: ServerDependencies,
249→  workspaceRecord: RecordId<"workspace", string>,
250→): Promise<RecordId<"conversation", string>> {
251→  const [onboardingRows] = await deps.surreal
252→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
253→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace AND source = 'onboarding' ORDER BY createdAt ASC LIMIT 1;",
254→      {
255→        workspace: workspaceRecord,
256→      },
257→    )
258→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
259→
260→  if (onboardingRows.length > 0) {
261→    return onboardingRows[0].id;
262→  }
263→
264→  const [latestRows] = await deps.surreal
265→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
266→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace ORDER BY createdAt DESC LIMIT 1;",
267→      {
268→        workspace: workspaceRecord,
269→      },
270→    )
271→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
272→
273→  if (latestRows.length > 0) {
274→    return latestRows[0].id;
275→  }
276→
277→  const now = new Date();
278→  const conversationRecord = new RecordId("conversation", randomUUID());
279→  await deps.surreal.create(conversationRecord).content({
280→    createdAt: now,
281→    updatedAt: now,
282→    workspace: workspaceRecord,
283→    source: "onboarding",
284→  });
285→  return conversationRecord;
286→}
287→
288→async function loadWorkspaceSeeds(
289→  deps: ServerDependencies,
290→  workspaceRecord: RecordId<"workspace", string>,
291→  limit: number,
292→): Promise<OnboardingSeedItem[]> {
293→  const [edgeRows] = await deps.surreal
294→    .query<[ProvenanceEdgeRow[]]>(
295→      [
296→        "SELECT id, `in`, out, confidence, extracted_at",
297→        "FROM extraction_relation",
298→        "WHERE `in` IN array::concat(",
299→        "  (SELECT VALUE id FROM message WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)),",
300→        "  (SELECT VALUE id FROM document_chunk WHERE workspace = $workspace)",
301→        ")",
302→        "ORDER BY extracted_at DESC",
303→        "LIMIT $limit;",
304→      ].join(" "),
305→      {
306→        workspace: workspaceRecord,
307→        limit,
308→      },
309→    )
310→    .collect<[ProvenanceEdgeRow[]]>();
311→
312→  const items: OnboardingSeedItem[] = [];
313→
314→  for (const edge of edgeRows) {
315→    const entityText = await readEntityText(deps.surreal, edge.out);
316→    if (!entityText) {
317→      continue;
318→    }
319→
320→    const sourceTable = edge.in.table.name;
321→    const entityTable = edge.out.table.name;
322→    const sourceKind = (sourceTable === "document_chunk" ? "document_chunk" : "message") as SourceKind;
323→    const sourceLabel = await readSourceLabel(deps, edge.in);
324→
325→    items.push({
326→      id: edge.out.id as string,
327→      kind: entityTable as EntityKind,
328→      text: entityText,
329→      confidence: edge.confidence,
330→      sourceKind,
331→      sourceId: edge.in.id as string,
332→      ...(sourceLabel ? { sourceLabel } : {}),
333→    });
334→  }
335→
336→  return items;
337→}
338→
339→async function readSourceLabel(deps: ServerDependencies, sourceRecord: SourceRecord): Promise<string | undefined> {
340→  const sourceTable = sourceRecord.table.name;
341→  if (sourceTable === "message") {
342→    const row = await deps.surreal.select<{ text: string }>(sourceRecord);
343→    if (!row) {
344→      return undefined;
345→    }
346→    return row.text.slice(0, 140);
347→  }
348→
349→  const chunk = await deps.surreal.select<{
350→    section_heading?: string;
351→    document: RecordId<"document", string>;
352→  }>(sourceRecord);
353→
354→  if (!chunk) {
355→    return undefined;
356→  }
357→
358→  const document = await deps.surreal.select<{ name: string }>(chunk.document);
359→  if (!document) {
360→    return chunk.section_heading;
361→  }
362→
363→  if (chunk.section_heading) {
364→    return `${document.name} · ${chunk.section_heading}`;
365→  }
366→
367→  return document.name;
